import { DefineComponent } from 'vue';
import Timeline from './index';

/**
 * Vue 3 wrapper. Use `<Timeline ... ref="timelineRef" />` and access the
 * underlying instance via `timelineRef.value?.current` (e.g. `current.next()`).
 */
declare const TimelineVue: DefineComponent<
    Timeline.Options,
    {},
    {
        el: HTMLElement | null;
        current: Timeline.Instance | null;
    }
>;

export default TimelineVue;
